return ['messages'=>['00a56749700c2703a7d0348ea3f6963d'=>'<strong>Posición actual: </strong><br>Catedrático de Física de Materia Condensada, UPV/EHU (1988- )<br>Presidente Donostia International Physics Center (DIPC) (1999-)<br>Presidente Junta Socios del BERC-MPC (Material Physics Center) (2009- )<br>Presidente de Honor de Jakiunde. Academia de Ciencias, Artes y Letras (2012-) ','2e5ce3944601a187cef77cde6fdaee95'=>'<strong>Conferencias, seminarios y publicaciones:</strong><br>Ha pronunciado conferencias plenarias e invitadas en más de un centenar de congresos internacionales.<br>Ha impartido seminarios en numerosos centros internacionales, como Cambridge, Berkeley, Berlín, Tokio,Viena, Londres, Osnabruek, Kioto, Zurich, Helsinki, Bariloche, Munich, Bell Labs New Jersey, IBMYorktown Hight, Buenos Aires, Oak Ridge, Brookhaven, Columbia, Florida, Nueva York, Méjico,Coimbra, Stuttgart, Kiel, Erlangen, Rutgers, Bielefeld, Lausanne, Tsukuba, Estrasburgo, Madburg entreotros.<br>Ha dirigido 27 Tesis doctorales y publicado más de 450 trabajos en libros y revistas especializadas (183Physical Review B (170) y Physical Review A (13), 48 Physical Review Letters, 9 en Nature o Science,etc).<br>Su interés investigador se centra en Física de muchos cuerpos, Física de Superficies, MicroscopíaElectrónica, Attofísica, e Interacción de cargas y radiación con la materia.<br>n.','62bf29dcacbdb62668dc9ca2a523338b'=>'<strong>Distinciones y Premios:</strong><br>Premio Extraordinario de Licenciatura, Nacional Fin de Carrera y Extraordinario de Doctorado<br>Overseas Fellow del Churchill College, Cambridge, Inglaterra (1985)<br>Fellow de la Sociedad Americana de Física (FAPS) (1990)<br>Premio Xabier María de Munibe (1996)<br>Premio “Dupont” (1996) Premio Euskadi de Investigación (1996)<br>Premio Príncipe de Viana de la Cultura (1997)<br>Medalla de oro de la Universidad del País Vasco. (1998)<br>Hijo Predilecto de la Villa de Isaba. (1998)<br>Gran Cruz de Alfonso X el Sabio (1998)<br>Premio Principe de Asturias de Investigación Científico Técnica (1998)<br>Max Planck Physics Prize (1998)<br>Vasco Universal del año (1998)<br>Medalla de Oro de la Ciudad de San Sebastián-Donostia (2000)<br>Fellow de la Asociación Americana para el Avance de la Ciencia (FAAAS) (2001)<br>Premio Iberdrola de Ciencia y Tecnología (2002)<br>Medalla de oro de la Real Sociedad Española de Física (2003)<br>Premio Manuel de Irujo. Fundación Irujo Etxea. Estella. (2003)<br>Premio Nacional Blas Cabrera de Ciencias Físicas de Materiales y de la Tierra (2005)<br>Medalla de oro de Gipuzkoa (2006)<br>Foreign Member of the Académie Royale des Sciences, des Lettres et des Beaux-Arts de Belgique (2009)<br>Premio Manel Xifra i Boada de Comunicación Científico-Técnica (2010)<br>Premio Sabino Arana (2011)<br>Miembro del Jurado de los Premios Príncipe de Asturias de Investigación Científica y Técnica (2006-2012)<br>Presidente Jurado de los Premios Príncipe de Asturias de Investigación Científica y Técnica (2012-)<br>Premio Liberpress Camins (2012)<br>Embajador Honorario Fundacional de San Sebastián (2012- )<br>Académico numerario de la Real Academia de Ciencias Exactas, Físicas y Naturales (RAC) (2014)<br>Medalla de Oro de Navarra (2016)<br>Miembro Honorario de la EPS (European Physical Society) (2018)     ','6428cf11fadd6ad5ed0b9140ed1da453'=>'<strong>Otros puestos anteriores:</strong><br>Catedrático de Física del Estado Sólido. Universidad de Barcelona (1978-1980)<br>Consejero de Educación del Gobierno Vasco (1980-1983)<br>Consejero de Educación y Cultura y portavoz del Gobierno Vasco (1983-1984)<br>Profesor Visitante en el Cavendish Laboratory, Universidad de Cambridge (U.K.) (1984-1986)<br>Miembro del Consejo Científico. Fundación BBV (1990-2009)<br>Miembro de la Comisión Trilateral (1996-2015)<br>Director Centro Mixto CSIC-UPV/EHU (1999-2001)<br>Consejero de IDOM (2000-2009)<br>Miembro del Consejo Rector Consejo Superior Investigaciones Científicas (CSIC) (2001-2007)<br>Presidente CIC Nanogune (2006-2019)<br>Presidente de Jakiunde. Academia de Ciencias, Artes y Letras (2007-2012)<br>Vicepresidente Innobasque (2008-2012 )<br>Consejero de IkerChem (2011- 2014)<br>Vicepresidente Fundación Euskampus (2011- 2019)<br>Presidente del Consejo Social de la Ciudad de San Sebastián (2015-2019)   ','6caa65ed7d0b81ef1893749d0df88868'=>'<strong>Actividades Profesionales:</strong><br>Miembro del Consejo Asesor Internacional del Campus de Excelencia de la Universidad de Oviedo (2010- )<br>Consejero de Graphenea SA (2011- )<br>Miembro del Patronato de la Fundación EDP (2016- )','6f68c54d46f42fd0249d2646675c129a'=>'<strong>Títulos Académicos:</strong><br>Licenciado en Ciencias Físicas. Universidad de Navarra (1972)<br>Philosophical Doctor (Ph. D). Universidad de Cambridge (U.K.) (1976<br>Doctor en Ciencias Físicas. Universidad Autónoma de Barcelona (1977)<br>Doctor of Science, (Sc. D.) University of Cambridge (1998)<br>Doctor Honoris Causa por las Universidades de Valladolid (2000), Pública de Navarra-UPNA (2008),Complutense de Madrid (2013), Aalto de Finlandia (2016) y Primada de América Autónoma de Santo Domingo (2017)   ','<strong>Aurreko beste lanpostu batzuk</strong>:<br/>Estatu Solidoko Fisikako katedraduna. Bartzelonako Unibertsitatea (1978-1980)<br/>Eusko Jaurlaritzako Hezkuntza sailburua (1980-1983)<br/>Hezkuntza eta Kultura sailburua eta Eusko Jaurlaritzaren bozeramailea (1983-1984)<br/>Cambridgeko Unibertsitateko (U.K.) Cavendish Laboratoryko irakasle bisitaria (1984-1986)<br/>Kontseilu Zientifikoko kidea. BBV Fundazioa (1990-2009)<br/>Hiru Aldeko Batzordeko kidea (1996-2015)<br/>CSIC-UPV/EHUko Zentro Mistoko zuzendaria (1999-2001)<br/>IDOMeko kontseilaria (2000-2009)<br/>Ikerketa Zientifikoen Goi Kontseiluaren Kontseilu Errektoreko kidea (CSIC) (2001-2007)<br/>CIC Nanoguneko presidentea (2006-2019)<br/>Jakiundeko lehendakaria. Zientzia, Arte eta Letren Akademia (2007-2012)<br/>Innobasque presidenteordea (2008-2012)<br/>IkerChem-eko kontseilaria (2011-2014)<